                    { step: 7, substrate: "Fumarate", product: "L-Malate", enzyme: "Fumarase", coenzyme: "" },
                    { step: 8, substrate: "L-Malate", product: "OAA", enzyme: "Malate DH", coenzyme: "NADH" }
