                    { infectionType: "Absent pus + neutrophilia + S. aureus",              deficiency: "LAD (adhesion)" },
                    { infectionType: "Recurrent Neisseria infections",                     deficiency: "Terminal complement C5–C9" },
                    { infectionType: "Encapsulated bacteria + SLE features",               deficiency: "Early complement C1q/C2/C4" },
                    { infectionType: "BCG-osis or vaccine-strain infection",               deficiency: "SCID / T cell deficiency" },
                    { infectionType: "Delayed umbilical separation + neutrophilia",        deficiency: "LAD" },
                    { infectionType: "Recurrent Neisseria + eczema + thrombocytopenia",    deficiency: "WAS (check triad)" }
