                            pollinators: ["Bees (most important terrestrial pollinators)", "Butterflies and moths", "Hoverflies", "Birds (hummingbirds, sunbirds)", "Bats (important for tropical flowers)", "Wind (non-animal; not mutualistic)"],
                            rewardToAnimals: "Nectar (carbohydrates, amino acids), pollen (protein)",
                            flowerAdaptations: ["Colour patterns (UV guides visible to bees)", "Scent", "Morphology (tube length matching pollinator tongue)", "Timing of opening"],
                            globalImportance: "~87% of flowering plant species depend on animal pollination; ~35% of global food production dependent on pollinators"
