                    byFunction: ["Energy source", "Energy storage", "Structural support", "Cell recognition and signalling"],
                    byCarbonylType: ["Aldoses (aldehyde group)", "Ketoses (ketone group)"],
                    byChainLength: ["Trioses (3C)", "Pentoses (5C)", "Hexoses (6C)"]
